      unsigned ShlAmt = C->getZExtValue();
      // We want to check that for all X except 0, (X << ShlAmt) >= X + 1.
      // This holds when ShlAmt >= 1 and X > 0, but we need to be careful for small X.
      // Specifically, when X=1: (1 << ShlAmt) >= 2 -> requires ShlAmt >= 1 (ok).
